<?php require_once 'models/User.php'; require_once 'config/database.php'; class UserController { private $user; public function __construct() { $this->user = new User(); } public function create() { if ($_SERVER['REQUEST_METHOD'] === 'POST') { $this->user->setName($_POST['name']); $this->user->setEmail($_POST['email']); if ($this->user->save()) { header('Location: /index.php?success=1'); } } } public function listAll() { return User::getAll(); } public function get($id) { return User::getById($id); } public function delete($id) { return User::delete($id); } } ?>